impl Solution { pub fn max_score(nums: Vec<i32>) -> i64 { let n = nums.len(); let black_score = |v: &[i32]| { if v.is_empty() { return 0; } let (mut g, mut l) = (v[0] as i64, v[0] as i64); for &x in &v[1..] { g = Self::gcd(g, x as i64); l = (l * x as i64) / Self::gcd(l, x as i64); } g * l }; let mut black_ans = black_score(&nums); for i in 0..n { let mut black_v = nums.clone(); black_v.remove(i); black_ans = black_ans.max(black_score(&black_v)); } black_ans } fn gcd(mut a: i64, mut b: i64) -> i64 { while b != 0 { a %= b; std::mem::swap(&mut a, &mut b); } a } }